// Input validation helpers for API endpoints.
//
// Each validator returns either null (valid) or a string describing why
// the value failed validation. The `validate` function runs a set of
// field rules against an input object and returns an array of error
// messages. `validationMiddleware` converts that into a 400 response.

// RFC 5321 caps the total length of an email address at 254 characters.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Reasonable email regex: local@domain.tld, no whitespace, requires a dot
// in the domain. Not a full RFC 5322 implementation — just enough to
// reject obviously malformed addresses.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateId(value, { field = 'id' } = {}) {
  if (!isPresent(value)) return `${field} is required`;
  // Accept numeric strings (e.g. from path/query params) as well as numbers.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber)) return `${field} must be numeric`;
  if (!Number.isInteger(asNumber) || asNumber <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

function validateName(value, { field = 'name' } = {}) {
  if (!isPresent(value)) return `${field} is required`;
  if (typeof value !== 'string') return `${field} must be a string`;
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    return `${field} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

function validateEmail(value, { field = 'email' } = {}) {
  if (!isPresent(value)) return `${field} is required`;
  if (typeof value !== 'string') return `${field} must be a string`;
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${field} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) return `${field} must be a valid email address`;
  return null;
}

// Map of validator name -> validator function. Makes it easy to declare
// rules as plain data: { id: 'id', name: 'name', email: 'email' }.
const VALIDATORS = {
  id: validateId,
  name: validateName,
  email: validateEmail,
};

/**
 * Run a schema of validators against an input object.
 *
 * @param {object} input  The object to validate (e.g. req.body, req.params).
 * @param {object} schema Map of field name -> validator key (from VALIDATORS).
 * @returns {string[]}    Array of error messages; empty if valid.
 */
function validate(input, schema) {
  const errors = [];
  const source = input || {};
  for (const [field, validatorKey] of Object.entries(schema)) {
    const validator = VALIDATORS[validatorKey];
    if (!validator) {
      throw new Error(`Unknown validator: ${validatorKey}`);
    }
    const error = validator(source[field], { field });
    if (error) errors.push(error);
  }
  return errors;
}

/**
 * Express middleware factory. Validates the specified request parts against
 * the provided schemas and responds with 400 if anything fails.
 *
 * Example:
 *   validationMiddleware({ params: { id: 'id' }, body: { name: 'name' } })
 */
function validationMiddleware(schemas) {
  return (req, res, next) => {
    const errors = [];
    for (const [part, schema] of Object.entries(schemas)) {
      errors.push(...validate(req[part], schema));
    }
    if (errors.length > 0) {
      return res.status(400).json({ error: 'Validation failed', details: errors });
    }
    return next();
  };
}

module.exports = {
  validate,
  validateId,
  validateName,
  validateEmail,
  validationMiddleware,
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};

