// Input validation helpers for API endpoints.
//
// Each validator returns either null (valid) or a string describing the
// validation failure. The `validate(...)` function composes a set of
// per-field checks and produces a list of error messages suitable for a
// 400 response body.

// RFC 5321 caps the total length of an email address at 254 characters.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Reasonably strict email regex: local@domain.tld with no whitespace and
// at least one dot in the domain. Intentionally not RFC-5322-complete —
// that's a rabbit hole — but it rejects the common mistakes.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(fieldName, value) {
  if (!isPresent(value)) {
    return `${fieldName} is required`;
  }
  return null;
}

function validateId(value, { fieldName = 'id' } = {}) {
  if (!isPresent(value)) {
    return `${fieldName} is required`;
  }
  // Accept numeric strings (from path/query params) and numbers.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !Number.isInteger(asNumber)) {
    return `${fieldName} must be a numeric integer`;
  }
  if (asNumber < 0) {
    return `${fieldName} must be a non-negative integer`;
  }
  return null;
}

function validateName(value, { fieldName = 'name', required = true } = {}) {
  if (!isPresent(value)) {
    return required ? `${fieldName} is required` : null;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    return `${fieldName} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

function validateEmail(value, { fieldName = 'email', required = true } = {}) {
  if (!isPresent(value)) {
    return required ? `${fieldName} is required` : null;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${fieldName} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

// Run a list of [message-or-null] checks and collect the failures.
// Returns { valid: boolean, errors: string[] }.
function collect(checks) {
  const errors = checks.filter((e) => e !== null && e !== undefined);
  return { valid: errors.length === 0, errors };
}

// Express middleware factory. `buildChecks(req)` should return an array of
// validator results (strings or nulls). On failure, responds with a 400
// and { error, details: [...] } and does NOT call next().
function validate(buildChecks) {
  return (req, res, next) => {
    const { valid, errors } = collect(buildChecks(req) || []);
    if (!valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  isPresent,
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  collect,
  validate,
};

