// validation.js
// Reusable input-validation helpers for API routes.
//
// Each validator returns `null` on success, or a string error message on failure.
// `validate(rules)` returns an Express middleware that runs a set of rules against
// the request (body / params / query) and, if any fail, responds with HTTP 400
// and a JSON body of the form:
//   { error: 'Validation failed', details: ['<message>', '<message>', ...] }

'use strict';

// RFC 5321 caps the whole address at 254 octets. We also require a minimally
// sensible "local@domain.tld" shape. This is intentionally strict-but-simple;
// full RFC 5322 parsing is out of scope.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const MAX_EMAIL_LENGTH = 254;
const MIN_NAME_LENGTH = 1;
const MAX_NAME_LENGTH = 100;

/** Field is present (not undefined, not null, not empty string). */
function isPresent(value) {
  if (value === undefined || value === null) return false;
  if (typeof value === 'string' && value.length === 0) return false;
  return true;
}

/** Numeric id: accepts numbers or numeric strings, must be a positive integer. */
function validateId(value, fieldName = 'id') {
  if (!isPresent(value)) return `${fieldName} is required`;
  const n = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(n)) return `${fieldName} must be numeric`;
  if (!Number.isInteger(n)) return `${fieldName} must be an integer`;
  if (n <= 0) return `${fieldName} must be a positive integer`;
  return null;
}

/** Name: non-empty string, 1-100 characters after trimming. */
function validateName(value, fieldName = 'name') {
  if (!isPresent(value)) return `${fieldName} is required`;
  if (typeof value !== 'string') return `${fieldName} must be a string`;
  const len = value.trim().length;
  if (len < MIN_NAME_LENGTH) {
    return `${fieldName} must be at least ${MIN_NAME_LENGTH} character`;
  }
  if (len > MAX_NAME_LENGTH) {
    return `${fieldName} must be at most ${MAX_NAME_LENGTH} characters`;
  }
  return null;
}

/** Email: string matching EMAIL_REGEX, max 254 chars. */
function validateEmail(value, fieldName = 'email') {
  if (!isPresent(value)) return `${fieldName} is required`;
  if (typeof value !== 'string') return `${fieldName} must be a string`;
  if (value.length > MAX_EMAIL_LENGTH) {
    return `${fieldName} must be at most ${MAX_EMAIL_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) return `${fieldName} must be a valid email address`;
  return null;
}

// ---------------------------------------------------------------------------
// Rule runner / middleware factory
// ---------------------------------------------------------------------------

// A rule is: { source: 'body'|'params'|'query', field: string, validator: fn, optional?: bool }
// `validator` is one of the functions above (or any `(value, fieldName) => string|null`).

function runRules(req, rules) {
  const errors = [];
  for (const rule of rules) {
    const container = req[rule.source] || {};
    const value = container[rule.field];

    if (rule.optional && !isPresent(value)) continue;

    const err = rule.validator(value, rule.field);
    if (err) errors.push(err);
  }
  return errors;
}

function validate(rules) {
  return function validationMiddleware(req, res, next) {
    const errors = runRules(req, rules);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  // Primitive validators (exported for direct use/testing)
  isPresent,
  validateId,
  validateName,
  validateEmail,

  // Rule runner + middleware factory
  runRules,
  validate,

  // Constants (useful in tests / docs)
  EMAIL_REGEX,
  MAX_EMAIL_LENGTH,
  MIN_NAME_LENGTH,
  MAX_NAME_LENGTH,
};

