// Validation helpers for API input.
//
// Each validator returns null on success or a descriptive error string on
// failure. `validate()` composes a schema of validators and returns a list of
// all validation errors for a given payload (so callers can report every
// problem at once, not just the first).

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

// ---- Field-level validators --------------------------------------------------

function required(value, field) {
  if (value === undefined || value === null || value === '') {
    return `${field} is required`;
  }
  return null;
}

function isNumericId(value, field = 'id') {
  const err = required(value, field);
  if (err) return err;
  // Accept numbers or numeric strings (e.g. route params come in as strings).
  const n = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(n) || !Number.isInteger(n) || n <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

function isString(value, field) {
  const err = required(value, field);
  if (err) return err;
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  return null;
}

function hasLength(value, field, min, max) {
  const err = isString(value, field);
  if (err) return err;
  if (value.length < min || value.length > max) {
    return `${field} must be between ${min} and ${max} characters`;
  }
  return null;
}

function isEmail(value, field = 'email') {
  const err = isString(value, field);
  if (err) return err;
  if (value.length > EMAIL_MAX) {
    return `${field} must be at most ${EMAIL_MAX} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

// ---- Composite validators ----------------------------------------------------

function validateName(value) {
  return hasLength(value, 'name', NAME_MIN, NAME_MAX);
}

function validateEmail(value) {
  return isEmail(value, 'email');
}

function validateId(value) {
  return isNumericId(value, 'id');
}

/**
 * Run a schema of validators against a payload and collect all errors.
 *
 * @param {object} payload - The object to validate (e.g. req.body).
 * @param {object} schema  - Map of field name -> validator function (value) => errOrNull.
 * @returns {string[]} List of error messages (empty if valid).
 */
function validate(payload, schema) {
  const errors = [];
  const source = payload && typeof payload === 'object' ? payload : {};
  for (const [field, validator] of Object.entries(schema)) {
    const err = validator(source[field]);
    if (err) errors.push(err);
  }
  return errors;
}

/**
 * Express middleware factory: validates req against the given schemas and
 * responds with 400 + a list of errors if any fail. Otherwise calls next().
 *
 * @param {object} schemas - { params?, body?, query? } each a validator schema.
 */
function validateRequest(schemas) {
  return (req, res, next) => {
    const errors = [];
    if (schemas.params) errors.push(...validate(req.params, schemas.params));
    if (schemas.body) errors.push(...validate(req.body, schemas.body));
    if (schemas.query) errors.push(...validate(req.query, schemas.query));
    if (errors.length > 0) {
      return res.status(400).json({ error: 'Validation failed', details: errors });
    }
    return next();
  };
}

module.exports = {
  // primitives
  required,
  isNumericId,
  isString,
  hasLength,
  isEmail,
  // composites
  validateId,
  validateName,
  validateEmail,
  // runners
  validate,
  validateRequest,
  // constants (exported for tests / reuse)
  NAME_MIN,
  NAME_MAX,
  EMAIL_MAX,
};

